function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check first part: 0...p strictly increasing
            let valid = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check second part: p...q strictly decreasing
            valid = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check third part: q...n-1 strictly increasing
            valid = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (valid) return true;
        }
    }
    return false;
}
